function currentXp(c=course()){const perItem=c.assignments.length===12?150:120,evidence=completedCount(c)+academyModules(c).filter(m=>state.academyPassed[m.id]).length+c.assignments.filter(a=>state.practicalAssessments[`${c.id}-PA${a.number}`]?.passed).length+c.assignments.filter(a=>state.witnessTestimonies[`${c.id}-WT${a.number}`]?.completed).length,academy=generalAcademyTests().filter(t=>state.academyTestPassed[t.id]).reduce((n,t)=>n+t.xp,0);return Math.min(10000,evidence*perItem+academy)}
