  {id:'materialmate',title:'Advanced Craftsperson',app:'MaterialMate',icon:'▦',need:Math.max(1,Math.ceil(n*.8)),description:'Materials, wastage and cost calculations.'},
  {id:'quotemate',title:'Construction Expert',app:'QuoteMate',icon:'£',need:n,description:'Plan, price and produce customer quotes.'}
