  const evidence=[{code:'AS',done:c.assignments.filter(a=>state.completed[`${c.id}-${a.number}`]).length,total:c.assignments.length,color:'#17665f'},{code:'TA',done:academyModules(c).filter(m=>state.academyPassed[m.id]).length,total:c.assignments.filter(a=>(a.ksbs||[]).some(x=>/^[KB]\d+/i.test(ksbCode(x)))).length,color:'#f0c600'},{code:'PA',done:c.assignments.filter(a=>state.practicalAssessments[`${c.id}-PA${a.number}`]?.passed).length,total:c.assignments.filter(a=>practicalSkills(a).length).length,color:'#bc70cb'},{code:'WT',done:c.assignments.filter(a=>state.witnessTestimonies[`${c.id}-WT${a.number}`]?.completed).length,total:c.assignments.length,color:'#55aeea'}];
