  const badgesDone=completedCount(c),rank=constructionRank(badgesDone,c.assignments.length),badges=c.assignments.map(a=>{const unlocked=!!state.completed[`${c.id}-${a.number}`];return `<div class="assignment-badge ${unlocked?'unlocked':'locked'}" title="Assignment ${a.number}: ${esc(a.title)}"><div class="badge-emblem"><span>${unlocked?badgeIcon(a.title):'·'}</span><small>${unlocked?'A+':a.number}</small></div><b>${unlocked?esc(a.title):`Badge ${a.number}`}</b></div>`}).join('');
