function unclaimedUnlockedRewards(){const c=course(),done=completedCount(c),xp=currentXp(c),main=titleRewards(c).filter(r=>done>=r.need&&!state.claimedRewards[r.id]).map(r=>({...r,type:'app'})),themes=themeRewards().filter(t=>xp>=t.xp&&!state.claimedThemes[t.id]).map(t=>({...t,type:'theme'}));return [...main,...themes]}
